head.script:
/*
 * 화 면 명 : 동부제철오더요청현황
 * 메뉴경로 : 엔콜/오더관리/3자물류/동부제철/
 * ASIS경로 : /ntis/dongwon-ntis-engine/src/main/webapp/tn/tp/dongbusteel/tp_201_01_01b.jsp
 * 작 성 자 : 유청아
 * 작 업 일 : 2026-02-20
 * 참고사항 : 1. tp_201_01_01p.jsp 삭제되어 작업장 상세 팝업 기능 제거
 *            2. ASIS : 동부제철오더요청등록 메뉴의 소스경로와 동부제철오더요청현황에서 호출되는 소스경로가 다름
 *               TOBE : 그리드 더블클릭 시 동부제철오더요청등록 화면으로 이동해야 하는데 위치는 아래와 같음(02.20 정소희책임과 협의완료)
 *               - 소스위치
 *                /ds/tp/dongbusteel/odrmgnt/tp_201_01_02t.jsp(탭메인)
 *                /ds/tp/dongbusteel/odrmgnt/tp_201_01_02b.jsp(오더요쳥등록 탭)
 *                /ds/tp/dongbusteel/odrmgnt/tp_201_01_03b.jsp(작업경로 상세등록 탭)
 *                /tn/tp/dongbusteel/tp_201_01_04b.jsp(해송작업경로 상세등록 탭)
 *               - 링크위치
 *                /ui/ds/tp/dongbusteel/odrmgnt/tp_201_01_02t.xml 
 *                /ui/ds/tp/dongbusteel/odrmgnt/tp_201_01_02b.xml 
 *                /ui/ds/tp/dongbusteel/odrmgnt/tp_201_01_03b.xml 
 *                /ui/ds/tp/dongbusteel/odrmgnt/tp_201_01_04b.xml 
 *            3. [작업지시등록] 버튼 삭제 : op_202_02_04b.jsp 프로그램이 NTIS 개발대상에 없음(DEBIS에서는 삭제됨)
 */

scwin.strCurDate = $c.date.getServerDateTime("yyyyMMdd");   // 현재일자
scwin.strPreDate = $c.date.addDate(scwin.strCurDate, -1);   // 전일
scwin.strNextDate = $c.date.addDate(scwin.strCurDate, 1);   // 다음일
scwin.userClsCd = $c.data.getMemInfo("userClsCd");
scwin.loginClntNo = $c.data.getMemInfo("clntNo");
scwin.loginClntNm = $c.data.getMemInfo("clntNm");

scwin.docCd = "ODRKND_001"; // 문서코드 - 화주오더종류
scwin.wrkPlCd = "999";      // 작업장코드 
scwin.itemCd = "";          // 항목코드 
scwin.pageTitle = "오더요청현황"
scwin.globalRow;

//-------------------------------------------------------------------------
// 화면로딩시
//-------------------------------------------------------------------------
scwin.onpageload = function () {
    if (scwin.userClsCd == "04") {
        scwin.pageTitle = "고객오더현황";
    }

    if (scwin.userClsCd == "01") {
        scwin.loginClntNo = "";
        scwin.loginClntNm = "";
    }

    // 입력 그리드 maxlength 설정
    scwin.f_SetGridColumnMaxLength(gr_shipmentIndicationOrderList);

    ed_mchtOdrNo.setMaxLength("20");
    ed_mchtOdrNo.setAllowChar("a-zA-Z0-9");
};

//-------------------------------------------------------------------------
// UDC Completed
//-------------------------------------------------------------------------
scwin.onUdcCompleted = function () {
    // 거래처명, 플랜트, 수요가 readOnly
    ed_clntNm.setReadOnly(true); // ASIS : class=input_textKorReadOnly
    ed_bizLongNm.setReadOnly(true);
    ed_dmndNm.setReadOnly(true);

    //초기화
    scwin.f_defaultValue();

    //타이틀 SET
    if (scwin.userClsCd == "04") {
        $c.data.setPopupTitle(scwin.pageTitle);
    }

    // 테스트 데이터
    // ed_mchtOdrFromDt.setValue("20260223");
    // ed_mchtOdrToDt.setValue("20260223");
};

//-------------------------------------------------------------------------
// 입력 그리드 maxlength 설정
//-------------------------------------------------------------------------
scwin.f_SetGridColumnMaxLength = function (gridViewObj) {
    for (let i = 0; i < gridViewObj.getTotalCol(); i++) {
        let colNm = gridViewObj.getColumnID(i);
        let dataObj = $c.gus.object(gridViewObj.getDataList());
        let colInfo = dataObj.getColumnInfo(colNm);

        if (typeof colInfo != "undefined") {
            gridViewObj.setMaxLength(i, colInfo.length);
        }
    }
};

//-------------------------------------------------------------------------
// 그리드 자가구분 컬럼
//-------------------------------------------------------------------------
scwin.f_retrieveGridLookup = function () {
    dma_selfClsCd.set("grpCd", "SD114");

    $c.sbm.execute(sbm_selfClsCd);
};

//-------------------------------------------------------------------------
// 초기화
//-------------------------------------------------------------------------
scwin.f_defaultValue = function () {
    // 조회 조건 초기화
    scwin.f_FieldClear();

    // 거래처 정보 설정
    ed_clntNo.setValue(OpConstants.ST_REPCLNTNO_STEEL); // 일단 동부 제강으로 ...

    if (!$c.gus.cfIsNull(ed_clntNo.getValue())) {
        scwin.f_openCommonPopUp(1, ed_clntNo.getValue(), ed_clntNm.getValue(), "T", "F");
    }

    $c.gus.cfEnableKeyData();
    $c.gus.cfDisableKey();

    ed_clntNo.focus();

    scwin.f_retrieveGridLookup();

    if (scwin.userClsCd != "01") {
        $c.gus.cfDisableObjects([ed_clntNo, ed_clntNm, btn_clntNo]);
    }
};

//-------------------------------------------------------------------------
// 두날짜 차이 계산
//-------------------------------------------------------------------------
scwin.f_DifferBetweenDate = function (sDateStr, eDateStr) {
    if ($c.date.diffDate(sDateStr, eDateStr) > 2) {
        return false;
    }
    return true;
};

//-------------------------------------------------------------------------
// 조회
//-------------------------------------------------------------------------
scwin.f_Retrieve = async function () {
    // 거래처 선택 확인
    if ($c.gus.cfIsNull(ed_clntNo.getValue())) {
        $c.gus.cfAlertMsg(MSG_CM_ERR_002, new Array("거래처"));
        ed_clntNo.focus();
        return false;
    }

    if ($c.str.trim(ed_mchtOdrFromDt.getValue()) === "") {
        ed_mchtOdrFromDt.setValue("");
    }
    if ($c.str.trim(ed_mchtOdrToDt.getValue()) === "") {
        ed_mchtOdrToDt.setValue("");
    }

    if (!scwin.f_DifferBetweenDate(ed_mchtOdrFromDt.getValue(), ed_mchtOdrToDt.getValue())) {
        $c.win.alert("화주오더(오더전송)일자 조회기간을 최대 3일까지만 조회해주세요.");
        ed_mchtOdrFromDt.focus();
        return;
    }

    // 오더기간 From - To 입력 확인
    var ret = await $c.gus.cfValidate([ed_mchtOdrFromDt, ed_mchtOdrToDt]);
    if (!ret) {
        return;
    }

    // 오더기간 범위 확인
    if (!$c.gus.cfIsAfterDate(ed_mchtOdrFromDt.getValue(), ed_mchtOdrToDt.getValue())) {
        cfAlertMsg(MSG_CM_ERR_048, new Array("화주오더일자 From", "화주오더일자 To"));
        ed_mchtOdrFromDt.focus();
        return false;
    }

    var diffObj = $c.gus.cfDifferBetween(ed_mchtOdrFromDt.getValue(), ed_mchtOdrToDt.getValue());

    // 오더기간이 1달 이상인경우 확인
    if (diffObj.year > 0 || diffObj.month > 0) {
        var confirmResult = await $c.win.confirm(["화주오더기간 이 1개월이 넘습니다.조회하시겠습니까?"]);
        if (!confirmResult) {
            ed_mchtOdrFromDt.focus();
            return false;
        }
    }

    dma_orderSearch.set("clntNo", scwin.hid_repClntNo); // 거래처번호
    ds_shipmentIndicationOrderList.setJSON([]); // OUT_DS 클리어

    $c.sbm.execute(sbm_reterieve);
};

//-------------------------------------------------------------------------
// 저장
//-------------------------------------------------------------------------
scwin.f_Save = async function () {
    var ret = await $c.gus.cfValidate([gr_shipmentIndicationOrderList]);
    if (!ret) {
        return;
    }

    //gr_shipmentIndicationOrderList.getCheckedIndex(columnInfo)
    var flag = 0;
    var countRow = ds_shipmentIndicationOrderList.getRowCount();
    var i = 0;
    while (i < countRow) {
        if (ds_shipmentIndicationOrderList.getCellData(i, "chk") == 1) {
            if (ds_shipmentIndicationOrderList.getCellData(i, "mcomOdrNo") != "") {
                await $c.win.alert("오더가 이미 생성되어 있습니다.");
                ds_shipmentIndicationOrderList.setCellData(i, "chk", 0);
                return;
            }

            if (ds_shipmentIndicationOrderList.getCellData(i, "beforeOdrTransWrkIndictYn") > 0) {
                await $c.win.alert("이전 오더가 이미 배차되었습니다.");
                ds_shipmentIndicationOrderList.setCellData(i, "chk", 0);
                return;
            }

            if (ds_shipmentIndicationOrderList.getCellData(i, "shipBizLongCd").trim() == '' ||
                ds_shipmentIndicationOrderList.getCellData(i, "shipBizLongCd").trim() == '-') {
                await $c.win.alert("출발작업장 데이터가 없습니다.");
                ds_shipmentIndicationOrderList.setCellData(i, "chk", 0);
                //f_WrkPlPopUp(i,'DPT'); TOBE : 작업장 상세 삭제
                return;
            }

            if (ds_shipmentIndicationOrderList.getCellData(i, "dptLobranCd").trim() == '') {
                await $c.win.alert("출발작업장의 소속지사 데이터가 없습니다.");
                ds_shipmentIndicationOrderList.setCellData(i, "chk", 0);
                return;
            }

            if (ds_shipmentIndicationOrderList.getCellData(i, "bizLongCd").trim() == '') {
                await $c.win.alert("사업장 데이터가 없습니다.");
                ds_shipmentIndicationOrderList.setCellData(i, "chk", 0);
                return;
            }

            if (ds_shipmentIndicationOrderList.getCellData(i, "dmndRgnCd").trim() == '') {
                await $c.win.alert("도착작업장 데이터가 없습니다.");
                ds_shipmentIndicationOrderList.setCellData(i, "chk", 0);
                return;
            }

            if (ds_shipmentIndicationOrderList.getCellData(i, "ctrtNo").trim() == '') {
                await $c.win.alert("계약 번호가 없습니다.");
                ds_shipmentIndicationOrderList.setCellData(i, "chk", 0);
                return;
            }
            if (ds_shipmentIndicationOrderList.getCellData(i, "ctrtWrkPathSeq") == '') {
                await $c.win.alert("계약 작업 경로가 없습니다.");
                ds_shipmentIndicationOrderList.setCellData(i, "chk", 0);
                return;
            }
            if (ds_shipmentIndicationOrderList.getCellData(i, "tplCommCd").trim() == '') {
                await $c.win.alert("제품코드가 없습니다.");
                ds_shipmentIndicationOrderList.setCellData(i, "chk", 0);
                return;
            }

            // 출발작업일자가 도착작업일자보다 큰 경우
            if (ds_shipmentIndicationOrderList.getCellData(i, "dptIntendDt").trim() > ds_shipmentIndicationOrderList.getCellData(i, "arvIntendDt").trim()) {
                $c.gus.cfAlertMsg(MSG_CM_ERR_057, new Array("도착예정일자", "출발예정일자"));
                return;
            }

            // 출발작업시간이 도착작업시간보다 큰 경우
            if (ds_shipmentIndicationOrderList.getCellData(i, "dptIntendDt").trim() == ds_shipmentIndicationOrderList.getCellData(i, "arvIntendDt").trim()
                && ds_shipmentIndicationOrderList.getCellData(i, "dptIntendHh").trim() > ds_shipmentIndicationOrderList.getCellData(i, "arvIntendHh").trim()) {
                $c.gus.cfAlertMsg(MSG_CM_ERR_057, new Array("도착예정시간", "출발예정시간"));
                return;
            }

            flag += 1;
            ++i;
        } else {
            ds_shipmentIndicationOrderList.removeRow(i);
            --countRow;
        }
    }

    if (flag == 0) {
        $c.win.alert("등록하실 오더데이터를 선택하십시요.");
        return;
    }

    var confirmResult = await $c.win.confirm("오더 일괄 등록을 실행 하시겠습니까?");
    if (confirmResult) {
        /*201602 화물위탁증 관련 추가 jisoo*/
        for (i = 0; i < ds_shipmentIndicationOrderList.getRowCount(); i++) {
            ds_shipmentIndicationOrderList.setCellData(i, "trnsRealMchtClntNm", "동부인천스틸 주식회사");
            ds_shipmentIndicationOrderList.setCellData(i, "trnsRealMchtClntTelNo", "02-3450-8450");
        }

        $c.sbm.execute(sbm_save);
    } else {
        scwin.f_Retrieve();
    }
};

//-------------------------------------------------------------------------
// 삭제
//-------------------------------------------------------------------------
scwin.f_delete = async function () {
    var ret = await $c.gus.cfValidate([gr_shipmentIndicationOrderList]);
    if (!ret) {
        return;
    }

    //gr_shipmentIndicationOrderList.getCheckedIndex(columnInfo)
    var flag = 0;
    var countRow = ds_shipmentIndicationOrderList.getRowCount();
    var i = 0;
    while (i < countRow) {
        if (ds_shipmentIndicationOrderList.getCellData(i, "chk") == 1) {
            if (ds_shipmentIndicationOrderList.getCellData(i, "mcomOdrNo") != "") {
                flag += 1;
                ++i;
            } else {
                $c.win.alert("동부오더로 확정한 오더만 삭제가능합니다.");
                return;
            }
        } else {
            ds_shipmentIndicationOrderList.removeRow(i);
            --countRow;
        }
    }

    if (flag == 0) {
        $c.win.alert("삭제하실 오더데이터를 선택하십시요.");
        return;
    }

    var confirmResult = await $c.win.confirm("오더 및 실적 일괄 삭제를 실행 하시겠습니까?");
    if (confirmResult) {
        $c.sbm.execute(sbm_delete);
    }
};

//-------------------------------------------------------------------------
// 계약순번 조회
//-------------------------------------------------------------------------
scwin.f_RetrieveCtrtWrkPathSeq = async function (row) {
    dma_contractOrderWorkPathQueryCondition.set("odrKndCd", ds_shipmentIndicationOrderList.getCellData(row, "mchtOdrKndCd")); // 화주오더종류
    dma_contractOrderWorkPathQueryCondition.set("repClntNo", ds_shipmentIndicationOrderList.getCellData(row, "repClntNo"));   // 대표 거래처번호
    dma_contractOrderWorkPathQueryCondition.set("selfClsCd", ds_shipmentIndicationOrderList.getCellData(row, "selfClsCd"));
    dma_contractOrderWorkPathQueryCondition.set("bizLongCd", ds_shipmentIndicationOrderList.getCellData(row, "coCd"));        // Shipping Point

    scwin.globalRow = row;

    $c.sbm.execute(sbm_reterieveCtrtWrkPathSeq);
};

scwin.f_setCtrtWrkPathSeq = function (ctrtWrkPathSeq, ctrtWrkPathNm) {
    ds_shipmentIndicationOrderList.setCellData(scwin.globalRow, "ctrtWrkPathSeq", ctrtWrkPathSeq);
    ds_shipmentIndicationOrderList.setCellData(scwin.globalRow, "ctrtWrkPathNm", ctrtWrkPathNm);
};

//-------------------------------------------------------------------------
// 조회 조건 초기화
//-------------------------------------------------------------------------
scwin.f_FieldClear = function () {
    $c.gus.cfInitObjects(tbl_searchCondition);

    ed_mchtOdrFromDt.setValue(scwin.strPreDate);
    ed_mchtOdrToDt.setValue(scwin.strNextDate);

    ed_clntNo.focus();
};

//-------------------------------------------------------------------------
// 공통 Popup 처리 : Gubun Code 에 따른 공통 Popup 을 호출한다.
//-------------------------------------------------------------------------
scwin.f_openCommonPopUp = function (disGubun, pCode, pName, pClose, pAllSearch) {
    // 선언부
    var pWhere; // 조회조건

    switch (disGubun) {
        case 1:
            // 거래처 팝업
            udc_clntNo.setSelectId("retrieveClntInfo2_tpro");   // XML상의 SELECT ID  
            udc_clntNo.cfCommonPopUp(scwin.udc_clntNo_callBackFunc // 콜백 함수
                , pCode // 화면에서의 ??? Code Element의 Value
                , pName // 화면에서의 ??? Name Element의 Value
                , pClose // 결과가 1건 일때 원도우를 AutoClose 여부 (T:Close,F:Opened)
                , null // 검색 결과 컬럼의 보여주는 개수 (SELECT절의 순서) MAX:10 - default (2)
                , null // Title순서
                , null // 보여주는 각 컬럼들의 폭
                , null // 컬럼중에서 숨기는 컬럼 지정
                , null // SQL절의 WHERE절에 원하는 조건을 선택함 MAX:8개까지 가능
                , null // POP-UP뛰을때 원도우의 사용자 정의 폭
                , null // POP-UP뛰을때 우도우의 사용자 정의 높이
                , null // 윈도우 위치 Y좌표
                , null // 윈도우 위치 X좌표
                , null // 중복체크여부 ("F")
                , pAllSearch // 전체검색허용여부 ("F")
                , "계약 거래처,거래처코드/명" // POP-UP Window Title 검색어1,2 ("Win타이틀,첫번검색Nm,두번?검색Nm")
            );

            break;

        case 2:
            // 사업장 팝업
            var v_clntNo = ed_clntNo.getValue();
            var v_itemCd = "COMPANY"; // 사업장 조회
            var v_wrkPlCd = scwin.wrkPlCd;

            // 거래처 선택 확인
            if ($c.gus.cfIsNull(v_clntNo)) {
                $c.gus.cfAlertMsg(MSG_CM_ERR_002, new Array("거래처"));
                ed_clntNo.focus();
                return false;
            }

            pWhere = v_clntNo + "," + v_itemCd + "," + v_wrkPlCd;

            udc_bizLongCd.setSelectId("retrieveEdiMapping_tpro"); // XML상의 SELECT ID  
            udc_bizLongCd.cfCommonPopUp(scwin.udc_bizLongCd_callBackFunc   // 콜백 함수
                , pCode // 화면에서의 ??? Code Element의 Value
                , pName // 화면에서의 ??? Name Element의 Value
                , pClose // 결과가 1건 일때 원도우를 AutoClose 여부 (T:Close,F:Opened)
                , null // 검색 결과 컬럼의 보여주는 개수 (SELECT절의 순서) MAX:10 - default (2)
                , null // Title순서
                , null // 보여주는 각 컬럼들의 폭
                , null // 컬럼중에서 숨기는 컬럼 지정
                , pWhere // SQL절의 WHERE절에 원하는 조건을 선택함 MAX:8개까지 가능
                , null // POP-UP뛰을때 원도우의 사용자 정의 폭
                , null // POP-UP뛰을때 우도우의 사용자 정의 높이
                , null // 윈도우 위치 Y좌표
                , null // 윈도우 위치 X좌표
                , null // 중복체크여부 ("F")
                , pAllSearch // 전체검색허용여부 ("F")
                , "공장,공장코드/명" // POP-UP Window Title 검색어1,2 ("Win타이틀,첫번검색Nm,두번?검색Nm")
            );

            break;

        case 3:
            if (!$c.gus.cfIsNull(ed_clntNo.getValue().trim())) {
                pWhere = ed_clntNo.getValue().trim();
            }

            // 수요가 팝업     
            udc_dmndNo.setSelectId("retrieveDmndList_tpro"); // XML상의 SELECT ID
            udc_dmndNo.cfCommonPopUp(scwin.udc_dmndNo_callBackFunc   // 콜백 함수
                , pCode // 화면에서의 ??? Code Element의 Value
                , pName // 화면에서의 ??? Name Element의 Value
                , pClose // 결과가 1건 일때 원도우를 AutoClose 여부 (T:Close,F:Opened)
                , null // 검색 결과 컬럼의 보여주는 개수 (SELECT절의 순서) MAX:10 - default (2)
                , null // Title순서
                , null // 보여주는 각 컬럼들의 폭
                , null // 컬럼중에서 숨기는 컬럼 지정
                , pWhere // SQL절의 WHERE절에 원하는 조건을 선택함 MAX:8개까지 가능
                , null // POP-UP뛰을때 원도우의 사용자 정의 폭
                , null // POP-UP뛰을때 우도우의 사용자 정의 높이
                , null // 윈도우 위치 Y좌표
                , null // 윈도우 위치 X좌표
                , null // 중복체크여부 ("F")
                , pAllSearch // 전체검색허용여부 ("F")
                , "수요가,수요가번호,수요가명" // POP-UP Window Title 검색어1,2 ("Win타이틀,첫번검색Nm,두번?검색Nm")
            );

            break;
    }
};

//-------------------------------------------------------------------------
// 팝업 처리시 검색된 데이터인 경우 팝업 처리 안함.
//-------------------------------------------------------------------------
scwin.f_chkOpenCommonPopUp = function (inObj, pairObj, disGubun, isCode) {
    // 값이 입력이 안된 경우, 해당 Text Box가 readonly 인 경우, 이전값과 동일한 경우 팝업을 실행하지 않음.
    if (!$c.gus.cfCanOpenPopup(inObj, pairObj))
        return;

    // 짝이 되는 오브젝트의 값 제거
    $c.gus.cfClearPairObj(pairObj);

    // 검색어 세팅
    var pVal = $c.gus.cfGetValue(inObj);

    // inObj가 코드 필드일 경우 팝업
    if (isCode == null || isCode == true)
        scwin.f_openCommonPopUp(disGubun, pVal, '', 'T', 'T');
    // inObj가 코드명 필드일 경우 팝업
    else
        scwin.f_openCommonPopUp(disGubun, '', pVal, 'T', 'T');
};

//-------------------------------------------------------------------------
// GRID에서 선택된 오더요청처리 : 해당 오더요청처리 페이지로 이동
//-------------------------------------------------------------------------
scwin.f_orderRequestProcess = function () {
    let row = ds_shipmentIndicationOrderList.getRowPosition();
    let strOrderRequestProcessUrl = "/ui/tn/tp/dongbusteel/tp_201_01_02t.xml";
    let pgmId = "tp_201_01_02t.jsp";

    if (row > -1) {
        var v_repClntNo = ds_shipmentIndicationOrderList.getCellData(row, "repClntNo");
        var v_clntNo = ds_shipmentIndicationOrderList.getCellData(row, "clntNo");
        var v_clntNm = ds_shipmentIndicationOrderList.getCellData(row, "clntNm");
        var v_mchtOdrKndCd = ds_shipmentIndicationOrderList.getCellData(row, "mchtOdrKndCd");
        var v_mchtOdrKndNm = ds_shipmentIndicationOrderList.getCellData(row, "mchtOdrKndNm");
        var v_mchtOdrNo = ds_shipmentIndicationOrderList.getCellData(row, "mchtOdrNo");
        var v_mcomOdrNo = ds_shipmentIndicationOrderList.getCellData(row, "mcomOdrNo");
        var v_logSeq = ds_shipmentIndicationOrderList.getCellData(row, "logSeq");

        if ($c.gus.cfIsNull(v_repClntNo)) {
            v_repClntNo = v_clntNo;
        }

        let paramObj = {
            repClntNo: v_repClntNo,
            clntNo: v_clntNo,
            clntNm: v_clntNm,
            mchtOdrKndCd: v_mchtOdrKndCd,
            mchtOdrKndNm: v_mchtOdrKndNm,
            mchtOdrNo: v_mchtOdrNo,
            mcomOdrNo: v_mcomOdrNo,
            logSeq: v_logSeq,
            type: "retrieve"
        };

        $c.win.openMenu("동부제철오더요청등록", strOrderRequestProcessUrl, pgmId, paramObj);
    } else {
        $c.gus.cfAlertMsg(MSG_CM_ERR_056, ["오더요청현황"]);
        return;
    }
};

