//-------------------------------------------------------------------------
// 그리드 셀 클릭 이벤트
// ASIS : gr_shipmentIndicationOrderList event=OnClick(Row,Colid)
//-------------------------------------------------------------------------

scwin.gr_shipmentIndicationOrderList_oncellclick = function (row, col) {
    debugger;
    let colId = gr_shipmentIndicationOrderList.getColumnID(col);
    let rowCnt = ds_shipmentIndicationOrderList.getRowCount();


    if (colId === "chk") {
        // [바디 셀] 체크박스를 눌렀을 때 (동일 오더번호(mchtOdrNo) 일괄 체크/해제)
        let curMchtOdrNo = ds_shipmentIndicationOrderList.getCellData(row, "mchtOdrNo");
        let curChkVal = ds_shipmentIndicationOrderList.getCellData(row, "chk");

        // 깜빡임 방지
        ds_shipmentIndicationOrderList.setBroadcast(false);

        for (let i = 0; i < rowCnt; i++) {
            if (row !== i) {
                let mchtOdrNo = ds_shipmentIndicationOrderList.getCellData(i, "mchtOdrNo");
                let mcomOdrNo = (ds_shipmentIndicationOrderList.getCellData(i, "mcomOdrNo") || "").trim();

                if (mchtOdrNo === curMchtOdrNo && mcomOdrNo === "") {
                    ds_shipmentIndicationOrderList.setCellData(i, "chk", curChkVal);
                }
            }
        }

        ds_shipmentIndicationOrderList.setBroadcast(true, true);
    } 
    else if (colId === "chk2") {
        let curMchtOdrNo = ds_shipmentIndicationOrderList.getCellData(row, "mchtOdrNo");
        let curTplCommCd = ds_shipmentIndicationOrderList.getCellData(row, "tplCommCd");
        let curChk2Val = ds_shipmentIndicationOrderList.getCellData(row, "chk2");

        // ds_shipmentIndicationOrderList.setBroadcast(false);

        for (let i = 0; i < rowCnt; i++) {
            if (row !== i) {
                let mchtOdrNo = ds_shipmentIndicationOrderList.getCellData(i, "mchtOdrNo");
                let mcomOdrNo = (ds_shipmentIndicationOrderList.getCellData(i, "mcomOdrNo") || "").trim();

                if (mchtOdrNo === curMchtOdrNo && mcomOdrNo === "") {
                    let tplCommCd = ds_shipmentIndicationOrderList.getCellData(i, "tplCommCd");

                    if (tplCommCd === curTplCommCd) {
                        ds_shipmentIndicationOrderList.setCellData(i, "chk2", curChk2Val);
                    } else {
                        // ds_shipmentIndicationOrderList.setBroadcast(true, true);

                        alert((i + 1) + "열은 품명이 다릅니다."); 
                        return; 
                    }
                }
            }
        }

        // ds_shipmentIndicationOrderList.setBroadcast(true, true);
    }
};

scwin.gr_shipmentIndicationOrderList_onheaderclick = function (headerId) {
    if (headerId === "column_chk") {
        let rowCnt = ds_shipmentIndicationOrderList.getRowCount();
        ds_shipmentIndicationOrderList.setBroadcast(false);


        for (let i = 0; i < rowCnt; i++) {
            let mcomOdrNo = (ds_shipmentIndicationOrderList.getCellData(i, "mcomOdrNo") || "").trim();
            let shipBizLongCd = (ds_shipmentIndicationOrderList.getCellData(i, "shipBizLongCd") || "").trim();
            let dmndRgnCd = (ds_shipmentIndicationOrderList.getCellData(i, "dmndRgnCd") || "").trim();
            let bizLongCd = (ds_shipmentIndicationOrderList.getCellData(i, "bizLongCd") || "").trim();
            let ctrtNo = (ds_shipmentIndicationOrderList.getCellData(i, "ctrtNo") || "").trim();
            let ctrtWrkPathSeq = (ds_shipmentIndicationOrderList.getCellData(i, "ctrtWrkPathSeq") || "").toString();
            let tplCommCd = (ds_shipmentIndicationOrderList.getCellData(i, "tplCommCd") || "").trim();
            let beforeOdrTransWrkIndictYn = ds_shipmentIndicationOrderList.getCellData(i, "beforeOdrTransWrkIndictYn");

            // AS-IS의 빡센 다중 조건
            if (mcomOdrNo === "" && 
                shipBizLongCd !== "" && 
                shipBizLongCd !== "-" && 
                dmndRgnCd !== "" && 
                bizLongCd !== "" && 
                ctrtNo !== "" && 
                ctrtWrkPathSeq !== "" && 
                tplCommCd !== "" && 
                beforeOdrTransWrkIndictYn == "0") {

                ds_shipmentIndicationOrderList.setCellData(i, "chk", "1"); 
            } else {
                ds_shipmentIndicationOrderList.setCellData(i, "chk", "0"); 
            }
        }

        ds_shipmentIndicationOrderList.setBroadcast(true, true);
    }
};
scwin.btn_apply_onclick = function (e) {
    for (let i = 0; i < ds_shipmentIndicationOrderList.getRowCount(); i++) {
        if(ds_shipmentIndicationOrderList.getCellData(i, "chk") ==='1'){
            ds_shipmentIndicationOrderList.setCellData(i, "dptIntendDt", cal_dptIntendDt.getValue());
        }
    }
};
